import React, { Component } from 'react';
import { useMediaQuery } from 'react-responsive'
import Iframe from 'react-iframe'
import ucsfLogo from './images/ucsfHealth.jpg'
import ucsfLogoWhite from './images/logowhite.jpg'
import { Fade } from 'react-slideshow-image'
import pnImage from './images/parnassus.jpeg'
import mzImage from './images/mz.jpg'
import mbImage from './images/mb.jpg'
import vaImage from './images/va.jpg'
import 'react-slideshow-image/dist/styles.css'
import pnImageD from './images/parnassus-2x.jpg'
import mzImageD from './images/mount-zion-2x.jpg'
import mbImageD from './images/mission-bay-2x.jpg'
import querystring from 'query-string'
import { properties } from '../../properties/properties.js'


const appName = "Care Activate"

const urlPA = "https://mcconxvip001.ucsfmedicalcenter.org/files/dhb/index.html?authentication=YL4nGlthWBLJFkezYffv6Zm7jjbhQ7G1K_4S0jWKbSE05LhylMV7TTs5dPZfkzba"
const urlMB = "https://mcconxvip001.ucsfmedicalcenter.org/files/dhb/index.html?authentication=YL4nGlthWBLJFkezYffv6dyHCGdN_NChZo4S_KmRlWt8n4N47-MoJtZ3H30vG0zY"
const urlMZ = "https://mcconxvip001.ucsfmedicalcenter.org/files/dhb/index.html?authentication=YL4nGlthWBLJFkezYffv6SNVBWj1OemrCLetZVQCrmkev1Tzt4hEtPc3imIxyMbZ"
const urlVA = "https://mcconxvip001.ucsfmedicalcenter.org/files/dhb/index.html?authentication=YL4nGlthWBLJFkezYffv6b0RZSnGOXJDPmfe8l0_XyiiEKyDhzJlvHSV_U36fObh"

const spanStyle = {
    padding: '20px',
    //background: '#efefef',
    color: '#000000'
  }

  const divStyle = {
    display: 'flex',
    alignItems: 'center',
    justifyContent: 'center',
    backgroundSize: 'cover',
    height: "100%"
  }

  const fadeImages = [
    {
      url: pnImage,
      caption: ''
    },
    {
      url: mbImage,
      caption: ''
    },
    {
      url: mzImage,
      caption: ''
    }
  ];

  const fadeImagesD = [
    {
      url: pnImageD,
      caption: ''
    },
    {
      url: mbImageD,
      caption: ''
    },
    {
      url: mzImageD,
      caption: ''
    }
  ];

  /*
const Desktop = ({ children }) => {
    const isDesktop = useMediaQuery({ minWidth: 992 })
    return isDesktop ? children : null
  }
  const Tablet = ({ children }) => {
    const isTablet = useMediaQuery({ minWidth: 768, maxWidth: 991 })
    return isTablet ? children : null
  }
  */
  const Mobile = ({ children }) => {
    const isMobile = useMediaQuery({ maxWidth: 767 })
    return isMobile ? children : null
  }
  const Default = ({ children }) => {
    const isNotMobile = useMediaQuery({ minWidth: 768 })
    return isNotMobile ? children : null
  }

  const boxStyleIn = {
    display: 'flex',
    cursor: 'pointer',
    backgroundColor: 'rgb(0, 191, 255)',
    color: 'green'
  } 

  const boxStyleOut = {
    display: 'flex',
    cursor: 'pointer',
    backgroundColor: 'lightblue',
    color: 'red'
  } 


  const boxStyle = {
    marginTop: "0px", width: "100%", display: "flex", border: "1px solid rgba(0, 0, 0, 0.05)",
    position: "relative", textDecoration: "none", color: "#007bff", padding: "35px 80px", fontSize: "20px",
    cursor: 'pointer'
  }

class responsive extends Component {

   constructor() {
      super();
      var today = new Date();
      this.state = { screen : 0, url: "", header: "", isHover: false, building: ""};

      //this.handleSubmit = this.handleSubmit.bind(this);




    }



 changeBackground(e) {
  e.target.style.backgroundColor = "#C0C0C0"
  //this.setState({isHover: true})
  //console.log(e.target)
  //e.target.style = boxStyleIn
}

changeBackgroundNormal(e) {
  e.target.style.backgroundColor = "#FFFFFF"
  //this.setState({isHover: false})
  //console.log(e.target)
  //e.target.style = boxStyleOut
}




    componentWillMount() {
      var query = querystring.parse(window.location.search);

      console.log(query.building)
      this.setState({building: query.building})

    }

    handleSetLink = (url, name) => {

        this.setState({url: url})
        //this.setState({screen: 0})
        this.setState({screen: 1})
        this.setState({header: name})


      }


      handleBack = () => {
        this.setState({screen: 0})
      }






   render() {

    var showDiv = "";




    try {
        /*
      Array.from(new Set(this.state.uploadResponse.map(groups => groups.date))).map(group => {return {date: group}}).map(Record =>(
        this.inputArrayData(Record.date, items)
        //console.dir(Record)
      ))*/

/*
      showDiv = <div>
      <div style={{margin: "0px", width: "100%", backgroundColor: "#052049", color: "#fff", padding: "10px"}}><img src={ucsfWordLogo} style={{padding: "5px"}} width="40px"></img> <span style={{}}>University of California San Francisco</span></div>

      <div style={{margin: "15px"}}><img src={ucsfLogo} width="150px"></img><hr></hr></div> 
      <div style={{marginTop: "20px", width: "100%", alignItems: "center", justifyContent: "center", display: "flex", fontSize: "30px"}}>

          Care Activate</div>

      <div style={{marginTop: "50px", width: "100%", alignItems: "center", justifyContent: "center", display: "flex"}}><button style={{width: "60%", height: "50px", textDecoration: "none", backgroundColor: "#052049", color: "#fff"}} onClick={() => {this.handleSetLink("https://mcconxvip001.ucsfmedicalcenter.org/files/dhb/index.html?authentication=YL4nGlthWBLJFkezYffv6Zm7jjbhQ7G1K_4S0jWKbSE05LhylMV7TTs5dPZfkzba", "Parnassus")}}>Parnassus</button></div>

      <div style={{marginTop: "20px", width: "100%", alignItems: "center", justifyContent: "center", display: "flex"}}><button style={{width: "60%", height: "50px", textDecoration: "none", backgroundColor: "#052049", color: "#fff"}} onClick={() => {this.handleSetLink("https://mcconxvip001.ucsfmedicalcenter.org/files/dhb/index.html?authentication=YL4nGlthWBLJFkezYffv6dyHCGdN_NChZo4S_KmRlWt8n4N47-MoJtZ3H30vG0zY", "Mission Bay")}}>Mission Bay</button></div>

      <div style={{marginTop: "20px", width: "100%", alignItems: "center", justifyContent: "center", display: "flex"}}><button style={{width: "60%", height: "50px", textDecoration: "none", backgroundColor: "#052049", color: "#fff"}} onClick={() => {this.handleSetLink("https://mcconxvip001.ucsfmedicalcenter.org/files/dhb/index.html?authentication=YL4nGlthWBLJFkezYffv6SNVBWj1OemrCLetZVQCrmkev1Tzt4hEtPc3imIxyMbZ", "Mount Zion")}}>Mount Zion</button></div>

      <div style={{marginTop: "20px", width: "100%", alignItems: "center", justifyContent: "center", display: "flex"}}><button style={{width: "60%", height: "50px", textDecoration: "none", backgroundColor: "#052049", color: "#fff"}} onClick={() => {this.handleSetLink("https://mcconxvip001.ucsfmedicalcenter.org/files/dhb/index.html?authentication=YL4nGlthWBLJFkezYffv6b0RZSnGOXJDPmfe8l0_XyiiEKyDhzJlvHSV_U36fObh", "VA")}}>VA</button></div>

      </div>
*/
if (this.state.building == undefined) {
      //if (this.state.screen == 0) {
        showDiv = <div>
            <Mobile>
            <div style={{marginTop: "20px", width: "100%", alignItems: "center", justifyContent: "center", display: "flex"}}><img src={ucsfLogo} width="150px" height="27px"></img></div> 
            <div style={{marginTop: "20px"}}>
                <div className="slide-container">
                  <Fade>
                  {fadeImages.map((fadeImages, index)=> (
                      <div key={index}>
                          <img src={fadeImages.url} width="100%"></img>
                          <div style={{position: "absolute", bottom: "8px", left: "16px", color: "#fff", fontSize: "25px", textShadow: "#CCCCCC 0px 0px 2px"}}>{appName}</div>
                      </div>
                    ))} 
                  </Fade>
                </div>
            </div>
            <div style={{marginTop: "20px", width: "100%", display: "flex"}}><a style={{width: "60%", textDecoration: "none", color: "#007bff", padding: "35px", fontSize: "20px", border: "1px solid rgba(0, 0, 0, 0.05)", width: "100%"}} href="?building=parnassus">Parnassus</a></div>
            <div style={{marginTop: "0px", width: "100%", display: "flex"}}><a style={{textDecoration: "none", color: "#007bff", padding: "35px", fontSize: "20px", border: "1px solid rgba(0, 0, 0, 0.05)", width: "100%"}} href="?building=missionbay">Mission Bay</a></div>
            <div style={{marginTop: "0px", width: "100%", display: "flex"}}><a style={{textDecoration: "none", color: "#007bff", padding: "35px", fontSize: "20px", border: "1px solid rgba(0, 0, 0, 0.05)", width: "100%"}} href="?building=mountzion">Mount Zion</a></div>
            <div style={{marginTop: "0px", width: "100%", display: "flex"}}><a style={{textDecoration: "none", color: "#007bff", padding: "35px", fontSize: "20px", border: "1px solid rgba(0, 0, 0, 0.05)", width: "100%"}} href="?building=va">VA</a></div>
            </Mobile>
            <Default>
                    <div style={{width: "100%", backgroundColor: "#052049", color: "#ffffff", height: "40px", fontSize: "14px"}}><span style={{left: "15px", top: "10px", position: "relative"}}>University of California San Francisco</span></div>

                    <div style={{width: "100%", height: "100px", boxShadow: "0px 0px 8px 2px #CCCCCC"}}><img src={ucsfLogo} style={{height: "30px", left: "10%", top: "35px", position: "relative"}}></img></div>

                    <div>
                <div className="slide-container">
                  <Fade>
                  {fadeImagesD.map((fadeImages, index)=> (
                      <div key={index} style={{textAlign: "center"}}>
                          <img src={fadeImages.url} width="95%"></img>
                          <div style={{position: "absolute", top: "110px", left: "80px", color: "#fff", fontSize: "50px", textShadow: "#CCCCCC 0px 0px 2px", fontWeight: "bold"}}>{appName}</div>
                      </div>
                    ))} 
                  </Fade>
                </div>
            </div>

            <div style={boxStyle}  onMouseEnter={this.changeBackground} onMouseLeave={this.changeBackgroundNormal} onClick={event => window.location.href='?building=parnassus'}>Parnassus</div>
            <div style={boxStyle}  onMouseEnter={this.changeBackground} onMouseLeave={this.changeBackgroundNormal} onClick={event => window.location.href='?building=missionbay'}>Mission Bay</div>
            <div style={boxStyle}  onMouseEnter={this.changeBackground} onMouseLeave={this.changeBackgroundNormal} onClick={event => window.location.href='?building=mountzion'}>Mount Zion</div>
            <div style={boxStyle}  onMouseEnter={this.changeBackground} onMouseLeave={this.changeBackgroundNormal} onClick={event => window.location.href='?building=va'}>VA</div>

            <div style={{width: "100%", backgroundColor: "#052049", color: "#ffffff",  fontSize: "14px",  padding: "50px"}}>

            <img src={ucsfLogoWhite} ></img>
                    <hr>
                    </hr>
                    © 2002 - 2023. The Regents of The University of California.


            </div>


            </Default>


        </div>

      }

      if (this.state.building != undefined) {


        var url = ""
        var headerTitle = ""


        if (this.state.building == "parnassus") {
          headerTitle = "Parnassus"
          url = urlPA
        }
        if (this.state.building == "missionbay") {
          headerTitle = "Mission Bay"
          url = urlMB
        }
        if (this.state.building == "mountzion") {
          headerTitle = "Mount Zion"
          url = urlMZ
        }
        if (this.state.building == "va") {
          headerTitle = "VA"
          url = urlVA
        }


      //if (this.state.screen == 1) {
        showDiv = <div>
        <Mobile>
          <div style={{display: "flex", flexFlow: "row wrap", marginTop: "15px", marginBottom: "15px"}}>
            <div style={{width: "33.3333%", textAlign: "left"}}>

              <a href={properties.frontendPath + "/button"} style={{left: "10px", position: "relative"}}>
                <div style={{width: "35px", height: "5px", backgroundColor: "#052049", margin: "6px 0"}}></div>
                <div style={{width: "35px", height: "5px", backgroundColor: "#052049", margin: "6px 0"}}></div>
                <div style={{width: "35px", height: "5px", backgroundColor: "#052049", margin: "6px 0"}}></div>
              </a>

              </div>
        <div style={{width: "33.3333%", textAlign: "center", fontSize: "20px", color: "#052049", fontWeight: "bold", marginTop: "5px"}}>
          {headerTitle}

        </div>
        <div style={{width: "33.3333%", textAlign: "right"}}>
        &nbsp;

        </div>

</div>



                <Iframe url={url}
            width="100%"
            height="800px"
            id=""
            className=""
            display="block"
            position="relative"/>

        </Mobile>
        <Default>
        <div style={{width: "100%", backgroundColor: "#052049", color: "#ffffff", height: "40px", fontSize: "14px"}}><span style={{left: "15px", top: "10px", position: "relative"}}>University of California San Francisco</span></div>



<div style={{display: "flex", flexFlow: "row wrap", marginTop: "15px", marginBottom: "15px", width: "100%"}}>
            <div style={{width: "97%", textAlign: "left"}}>
            <div style={{width: "100%", height: "50px"}}>
              <span style={{height: "30px", left: "20px", top: "10px", position: "relative", fontSize: "25px"}}>{headerTitle}</span></div>



              </div>

        <div style={{width: "3%", textAlign: "right", alignItems: "right"}}>
              <a href={properties.frontendPath + "/button"} style={{top: "5px", position: "relative"}}>
                <div style={{width: "35px", height: "5px", backgroundColor: "#052049", margin: "6px 0"}}></div>
                <div style={{width: "35px", height: "5px", backgroundColor: "#052049", margin: "6px 0"}}></div>
                <div style={{width: "35px", height: "5px", backgroundColor: "#052049", margin: "6px 0"}}></div>
              </a>
        </div>

</div>







                <Iframe url={url}
            width="100%"
            height="600px"
            id=""
            className=""
            display="block"
            position="relative"/>
            <div style={{width: "100%", backgroundColor: "#052049", color: "#ffffff",  fontSize: "14px",  padding: "50px"}}>

              <img src={ucsfLogoWhite} ></img>
                      <hr>
                      </hr>
                      © 2002 - 2023. The Regents of The University of California.


              </div>
        </Default>
        </div>
      }

    } catch (e) {
      showDiv = "You don't have permission for using this application!"
    }




      return (
        <div style={{minHeight: "500px", marginLeft: "0px", marginRight: "0px"}}>{showDiv}</div>
       )
   }
 }

 //<div><pre>{JSON.stringify(this.state.uploadResponse, null, 2) }</pre></div>

 export default responsive;
